403: func (srv *Server) closeListenersLocked() error {
404: 	var err error
405: 	for ln := range srv.listeners {
406: 		if cerr := ln.Close(); cerr != nil && err == nil {
407: 			err = cerr
408: 		}
409: 		delete(srv.listeners, ln)
410: 	}
411: 	return err
412: }
