35: // WithMiddleware composes the provided Middleware and return a ssh.Option.
36: // This useful if you manually create an ssh.Server and want to set the
37: // Server.Handler.
38: //
39: // Notice that middlewares are composed from first to last, which means the last one is executed first.
40: func WithMiddleware(mw ...Middleware) ssh.Option {
41: 	return func(s *ssh.Server) error {
42: 		h := func(s ssh.Session) {}
43: 		for _, m := range mw {
44: 			h = m(h)
45: 		}
46: 		s.Handler = h
47: 		return nil
48: 	}
