51: // WithHostKeyFile returns an ssh.Option that sets the path to the private.
52: func WithHostKeyPath(path string) ssh.Option {
53: 	if _, err := os.Stat(path); os.IsNotExist(err) {
54: 		dir, f := filepath.Split(path)
55: 		n := strings.TrimSuffix(f, "_ed25519")
