90: // WithTrustedUserCAKeys authorize certificates that are signed with the given
91: // Certificate Authority public key, and are valid.
92: // Analogous to the TrustedUserCAKeys OpenSSH option.
93: func WithTrustedUserCAKeys(path string) ssh.Option {
94: 	return func(s *ssh.Server) error {
95: 		cas, err := parseAuthorizedKeys(path)
96: 		if err != nil {
97: 			return err
98: 		}
99: 
100: 		return WithPublicKeyAuth(func(ctx ssh.Context, key ssh.PublicKey) bool {
101: 			cert, ok := key.(*gossh.Certificate)
102: 			if !ok {
103: 				// not a certificate...
104: 				return false
105: 			}
106: 
107: 			checker := &gossh.CertChecker{
108: 				IsUserAuthority: func(auth gossh.PublicKey) bool {
109: 					for _, ca := range cas {
110: 						if bytes.Equal(auth.Marshal(), ca.Marshal()) {
111: 							// its a cert signed by one of the CAs
112: 							return true
113: 						}
114: 					}
115: 					// it is a cert, but signed by another CA
116: 					return false
117: 				},
118: 			}
119: 
120: 			if !checker.IsUserAuthority(cert.SignatureKey) {
121: 				return false
122: 			}
123: 
124: 			if err := checker.CheckCert(ctx.User(), cert); err != nil {
125: 				return false
126: 			}
127: 
128: 			return true
129: 		})(s)
130: 	}
131: }
