133: func parseAuthorizedKeys(path string) ([]ssh.PublicKey, error) {
134: 	var keys []ssh.PublicKey
135: 
136: 	f, err := os.Open(path)
137: 	if err != nil {
138: 		return keys, fmt.Errorf("failed to parse %q: %w", path, err)
139: 	}
140: 	defer f.Close() // nolint: errcheck
141: 
142: 	rd := bufio.NewReader(f)
143: 	for {
144: 		line, _, err := rd.ReadLine()
145: 		if err != nil {
146: 			if errors.Is(err, io.EOF) {
147: 				break
148: 			}
149: 			return keys, fmt.Errorf("failed to parse %q: %w", path, err)
150: 		}
151: 		upk, _, _, _, err := ssh.ParseAuthorizedKey(line)
152: 		if err != nil {
153: 			return keys, fmt.Errorf("failed to parse %q: %w", path, err)
154: 		}
155: 		keys = append(keys, upk)
156: 	}
157: 	return keys, nil
158: }
